const response = $('Fetch Recent Matches').first().json;
const matchLog = $('Read Match Log').all();

const matches = response.data || [];

// Build set of already analyzed match IDs
const analyzedIds = new Set(
  matchLog
    .filter(r => r.json.analyzed === 'true' || r.json.analyzed === true)
    .map(r => r.json.match_id)
);

// Find completed IPL match not yet analyzed
const completedIPL = matches.find(m => {
  const name = (m.name || '').toUpperCase();
  const isIPL = name.includes('IPL') || 
                name.includes('INDIAN PREMIER LEAGUE');
  const isT20 = (m.matchType || '').toLowerCase() === 't20';
  const isCompleted = m.matchStarted === true && 
                      m.matchEnded === true;
  const notAnalyzed = !analyzedIds.has(m.id);
  return isIPL && isT20 && isCompleted && notAnalyzed;
});

// Fallback for testing — use any completed T20
const fallback = matches.find(m =>
  (m.matchType || '').toLowerCase() === 't20' &&
  m.matchStarted === true &&
  m.matchEnded === true &&
  m.score && m.score.length >= 2 &&
  !analyzedIds.has(m.id)
);

const match = completedIPL || fallback;

if (!match) {
  return [{ json: { skip: true, reason: 'No new completed matches' } }];
}

// Parse scores
const scores = match.score || [];
const innings1 = scores[0] || {};
const innings2 = scores[1] || {};

// Determine winner from status string
const status = match.status || '';

return [{
  json: {
    skip: false,
    matchId: match.id,
    matchName: match.name,
    matchDate: match.date,
    teams: match.teams || [],
    team1: match.teams?.[0] || 'Team A',
    team2: match.teams?.[1] || 'Team B',
    status,
    innings1Score: `${innings1.r || 0}/${innings1.w || 0} (${innings1.o || 0} ov)`,
    innings2Score: `${innings2.r || 0}/${innings2.w || 0} (${innings2.o || 0} ov)`,
    innings1Runs: innings1.r || 0,
    innings1Wickets: innings1.w || 0,
    innings1Overs: innings1.o || 0,
    innings2Runs: innings2.r || 0,
    innings2Wickets: innings2.w || 0,
    innings2Overs: innings2.o || 0,
    isLiveIPL: !!completedIPL
  }
}];

const analyses = $input.all();

if (analyses.length === 0) {
  return [{ json: { skip: true, reason: 'No analyses this week' } }];
}

// Get last 7 days of analyses
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

const thisWeek = analyses.filter(a => {
  const matchDate = new Date(a.json.date);
  return matchDate >= sevenDaysAgo;
});

if (thisWeek.length === 0) {
  return [{ json: { skip: true, reason: 'No matches this week' } }];
}

let matchSummaries = '';
thisWeek.forEach((a, i) => {
  matchSummaries += `Match ${i+1}: ${a.json.match_name}
Result: ${a.json.winner}
Player of Match: ${a.json.player_of_match || 'N/A'}
Summary: ${a.json.analysis_summary}
\n`;
});

const prompt = `You are an IPL cricket journalist writing a weekly roundup newsletter.

This week's IPL matches:
${matchSummaries}

Generate a weekly digest in this JSON format:
{
  "week_headline": "Catchy headline summarizing this week's IPL action",
  "week_intro": "2-3 sentence intro capturing the week's drama and key themes",
  "match_recaps": [
    {
      "match": "match name",
      "one_liner": "One punchy sentence recap of the match"
    }
  ],
  "player_of_week": "Name and one sentence on the standout performer of the week",
  "week_talking_point": "The biggest talking point or controversy from this week",
  "next_week_preview": "2 sentences building anticipation for next week's matches"
}

Rules:
- Write like a cricket journalist
- Be opinionated and engaging
- Use cricket language fans love`;

return [{
  json: {
    prompt,
    matchCount: thisWeek.length,
    weekOf: new Date().toDateString()
  }
}];

